{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem is a topological embedding task where we need to compress a colored grid into a smaller footprint (more zeros) while preserving connectivity and adjacency. This requires graph theory analysis and a layout algorithm.",
  "helpers": [
    {
      "label": "graph_analyzer",
      "instructions": "Analyze the input 50x50 grid to construct a graph where each node represents a color (1 to M). For each node, determine its connectivity (which colors it is adjacent to) and its internal connectivity (the shape/topology of the color's original cells). Identify if any color forms a ring or a complex shape that might require specific spatial arrangements."
    },
    {
      "label": "layout_optimizer",
      "instructions": "Given a graph of color adjacencies and the topological constraints of each color, propose a compact 50x50 grid layout. The goal is to minimize the number of cells used by each color (to maximize zeros) while ensuring that if two colors were adjacent in the input, they are adjacent in the output, and no new color adjacencies are created. Consider using a skeleton-based approach or a grid-based embedding algorithm."
    },
    {
      "label": "code_generator",
      "instructions": "Write a complete main.py script that reads the 50x50 grid from stdin, implements a valid (even if simple) algorithm to satisfy the connectivity and adjacency constraints, and prints the resulting 50x50 grid to stdout. Ensure the script handles the input format correctly and adheres to the strict output requirements."
    }
  ],
  "synthesis_brief": "Combine the adjacency graph and topological constraints from the graph_analyzer with the spatial layout strategy from the layout_optimizer to create a robust embedding algorithm. Finally, use the code_generator to implement this logic into a production-ready main.py file."
}

